def fib_memo(n: int) -> int:
    if n < 0:
        raise ValueError("n must be a non-negative integer")
    memo = {0: 0, 1: 1}
    def fib(k):
        if k not in memo:
            memo[k] = fib(k - 1) + fib(k - 2)
        return memo[k]
    return fib(n)
