def solve_quadratic(a: float, b: float, c: float) -> tuple:
    if a == 0:
        if b == 0:
            return ()
        return (-c / b,)
    discriminant = b * b - 4 * a * c
    if discriminant < 0:
        return ()
    if discriminant == 0:
        root = -b / (2 * a)
        return (root,)
    sqrt_disc = discriminant ** 0.5
    root1 = (-b + sqrt_disc) / (2 * a)
    root2 = (-b - sqrt_disc) / (2 * a)
    return (root1, root2)
```

