def reverse_words(sentence):
    import re
    parts = re.split(r'(\s+|\W+)', sentence)
    words = [p for p in parts if re.match(r'\w+', p)]
    reversed_words = words[::-1]
    result = []
    word_idx = 0
    for part in parts:
        if re.match(r'\w+', part):
            result.append(reversed_words[word_idx])
            word_idx += 1
        else:
            result.append(part)
    return ''.join(result)
```

