    separators = []
    for part in parts:
        if part == '':
            continue
        if re.match(r'^\s+$', part) or re.match(r'^[^\w\s]+$', part):
            separators.append(part)
        else:
            words.append(part)
    words.reverse()
    result = []
    word_idx = 0
    sep_idx = 0
    for part in parts:
        if part == '':
            continue
        if re.match(r'^\s+$', part) or re.match(r'^[^\w\s]+$', part):
            result.append(separators[sep_idx])
            sep_idx += 1
        else:
            result.append(words[word_idx])
            word_idx += 1
    return ''.join(result)
