def reverse_words(s):
    import re
    tokens = re.split(r'(\s+)', s)
    words = [t for t in tokens if t.strip() != '']
    spaces = [t for t in tokens if t.strip() == '']
    if not words:
        return s
    reversed_words = words[::-1]
    result = []
    if s and s[0].isspace():
        result.append(spaces[0] if spaces else '')
        for i, word in enumerate(reversed_words):
            result.append(word)
            if i < len(spaces) - 1:
                result.append(spaces[i+1])
    else:
        for i, word in enumerate(reversed_words):
            result.append(word)
            if i < len(spaces):
                result.append(spaces[i])
    return ''.join(result)
