def generate_permutations(elements):
    if len(elements) <= 1:
        return [elements[:]]

    result = []
    for i in range(len(elements)):
        first = elements[i]
        rest = elements[:i] + elements[i+1:]
        for perm in generate_permutations(rest):
            result.append([first] + perm)

    return result
