import re
from urllib.parse import urlparse

def is_valid_url(url: str) -> bool:
    if not isinstance(url, str):
        return False
    try:
        result = urlparse(url)
        if result.scheme not in ('http', 'https'):
            return False
        if not result.netloc:
            return False
        # Check for valid hostname or IP address
        host = result.hostname
        if host is None:
            return False
        # Hostname must not be empty and must match allowed characters
        if not re.match(r'^[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z0-9]([a-zA-Z0-9\-]{0,61}[a-zA-Z0-9])?)*$', host):
            # Also allow IPv6 addresses in brackets
            if not (host.startswith('[') and host.endswith(']')):
                return False
        # Ensure no invalid characters in the entire URL
        if re.search(r'[\s<>\"{}|\\^`]', url):
            return False
        return True
    except Exception:
        return False
