from typing import Dict, List, Any

def depth_first_search(graph: Dict[Any, List[Any]], start: Any) -> List[Any]:
    if start not in graph:
        return []

    visited = set()
    result = []

    def dfs(node: Any) -> None:
        visited.add(node)
        result.append(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                dfs(neighbor)

    dfs(start)
    return result
