def solve_quadratic(a, b, c):
    if a == 0:
        if b == 0:
            return ()
        return (-c / b,)
    discriminant = b**2 - 4 * a * c
    if discriminant < 0:
        return ()
    sqrt_disc = discriminant**0.5
    root1 = (-b + sqrt_disc) / (2 * a)
    root2 = (-b - sqrt_disc) / (2 * a)
    if discriminant == 0:
        return (root1,)
    return (root1, root2)
