def main():
    numbers = range(1, 11)
    valid_combos = []
    for combo in itertools.combinations(numbers, 5):
        if sum(combo) == 27:
            valid_combos.append(combo)

    # Collect all numbers that appear in at least one valid combination
    possible_numbers = set()
    for combo in valid_combos:
        possible_numbers.update(combo)

    # Find numbers that never appear
    impossible_numbers = set(numbers) - possible_numbers

    # The puzzle implies exactly one such number
    if len(impossible_numbers) == 1:
        print(impossible_numbers.pop())
    else:
        # If multiple, print them sorted; but we expect one
        print(sorted(impossible_numbers))

if __name__ == "__main__":
